const original = $('Extract Review + Groq Key').first().json;
const raw = $json.choices[0].message.content;
let parsed;
try {
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(jsonMatch ? jsonMatch[0] : raw);
} catch (e) {
  parsed = { sentiment: 'neutral', theme: 'Other', confidence: 0 };
}
return [{
  json: {
    Timestamp: new Date().toISOString(),
    ProductName: original.productName || '',
    ReviewText: original.reviewText,
    Rating: original.rating,
    Sentiment: parsed.sentiment || 'neutral',
    Theme: parsed.theme || 'Other',
    Confidence: parsed.confidence ?? 0,
    groqApiKey: original.groqApiKey
  }
}];

const reviews = $input.all().map(i => i.json);
const groqApiKey = $('Parse Review Classification').first().json.groqApiKey;

const byTheme = {};
for (const r of reviews) {
  const theme = r.Theme || 'Other';
  if (!byTheme[theme]) byTheme[theme] = { theme, count: 0, negativeCount: 0, examples: [] };
  byTheme[theme].count += 1;
  if (r.Sentiment === 'negative') byTheme[theme].negativeCount += 1;
  if (byTheme[theme].examples.length < 2 && r.Sentiment === 'negative') byTheme[theme].examples.push(r.ReviewText);
}

const totalCount = reviews.length;
const totalNegative = reviews.filter(r => r.Sentiment === 'negative').length || 1;

const ranked = Object.values(byTheme).map(t => ({
  ...t,
  negativeShare: Math.round((t.negativeCount / t.count) * 100) / 100,
  priorityScore: Math.round(((t.count / totalCount) * 0.4 + (t.negativeCount / totalNegative) * 0.6) * 100) / 100
})).sort((a, b) => b.priorityScore - a.priorityScore);

return [{ json: { rankedThemes: ranked, groqApiKey, totalReviews: totalCount } }];

const rankedThemes = $('Aggregate Themes By Impact').first().json.rankedThemes;
const totalReviews = $('Aggregate Themes By Impact').first().json.totalReviews;
const raw = $json.choices[0].message.content;

const summaryMatch = raw.match(/SUMMARY:\s*([\s\S]*?)(?=RECOMMENDATION FOR|$)/i);
const summary = summaryMatch ? summaryMatch[1].trim() : '';

const recMatches = [...raw.matchAll(/RECOMMENDATION FOR ([^:]+):\s*([\s\S]*?)(?=RECOMMENDATION FOR|$)/gi)];
const recommendations = recMatches.map(m => ({ theme: m[1].trim(), action: m[2].trim() }));

const bannedPhrases = ['monitor the situation', 'no action needed', 'continue as is', 'keep an eye on', 'improve quality'];
const checks = [];
const topN = Math.min(3, rankedThemes.length);
if (!summary) checks.push('missing executive summary');
if (recommendations.length < topN) checks.push('fewer recommendations than top themes (' + recommendations.length + ' vs ' + topN + ')');
for (const r of recommendations) {
  const lower = r.action.toLowerCase();
  if (r.action.split(/\s+/).length < 6) checks.push('recommendation for ' + r.theme + ' too short or vague');
  for (const bp of bannedPhrases) {
    if (lower.includes(bp)) checks.push('recommendation for ' + r.theme + ' uses a vague placeholder phrase');
  }
}

const verdict = checks.length ? 'FAIL' : 'PASS';

return [{ json: { rankedThemes, totalReviews, summary, recommendations, verdict, failedChecks: checks } }];

const runDate = new Date().toISOString();
return $json.rankedThemes.map(t => {
  const rec = $json.recommendations.find(r => r.theme === t.theme);
  return {
    json: {
      RunDate: runDate,
      Status: 'READY',
      Theme: t.theme,
      Count: t.count,
      NegativeSharePct: Math.round(t.negativeShare * 100),
      PriorityScore: t.priorityScore,
      Recommendation: rec ? rec.action : '',
      Summary: $json.summary
    }
  };
});

const runDate = new Date().toISOString();
return $json.rankedThemes.slice(0,3).map(t => ({
  json: {
    RunDate: runDate,
    Status: 'NEEDS REVIEW',
    Theme: t.theme,
    Count: t.count,
    NegativeSharePct: Math.round(t.negativeShare * 100),
    PriorityScore: t.priorityScore,
    Recommendation: 'QA flagged: ' + $json.failedChecks.join('; '),
    Summary: $json.summary
  }
}));
